# Security configurations
MAX_QUERY_DEPTH = 5
MAX_QUERY_COMPLEXITY = 100
MAX_ALIASES = 10
RATE_LIMIT_REQUESTS = 100
RATE_LIMIT_WINDOW = 60  # seconds

# Rate limiting storage
rate_limit_storage = defaultdict(list)

# Query complexity costs
COMPLEXITY_COSTS = {
    'Product': 1,
    'Category': 1,
    'Review': 1,
    'products': 2,
    'categories': 2,
    'reviews': 3,
}


def get_client_ip():
    if request.headers.get('X-Forwarded-For'):
        return request.headers.get('X-Forwarded-For').split(',')[0]
    return request.remote_addr


def rate_limit_check():
    client_ip = get_client_ip()
    current_time = time.time()
    
    # Clean old entries
    rate_limit_storage[client_ip] = [
        timestamp for timestamp in rate_limit_storage[client_ip]
        if current_time - timestamp < RATE_LIMIT_WINDOW
    ]
    
    # Check rate limit
    if len(rate_limit_storage[client_ip]) >= RATE_LIMIT_REQUESTS:
        raise GraphQLError(f"Rate limit exceeded. Maximum {RATE_LIMIT_REQUESTS} requests per {RATE_LIMIT_WINDOW} seconds.")
    
    rate_limit_storage[client_ip].append(current_time)


def calculate_query_depth(node, depth=0):
    if depth > MAX_QUERY_DEPTH:
        raise GraphQLError(f"Query depth exceeds maximum allowed depth of {MAX_QUERY_DEPTH}")
    
    if not hasattr(node, 'selection_set') or not node.selection_set:
        return depth
    
    max_depth = depth
    for selection in node.selection_set.selections:
        if hasattr(selection, 'selection_set'):
            current_depth = calculate_query_depth(selection, depth + 1)
            max_depth = max(max_depth, current_depth)
    
    return max_depth


def calculate_query_complexity(node, complexity=0):
    if complexity > MAX_QUERY_COMPLEXITY:
        raise GraphQLError(f"Query complexity exceeds maximum allowed complexity of {MAX_QUERY_COMPLEXITY}")
    
    if not hasattr(node, 'selection_set') or not node.selection_set:
        return complexity
    
    total_complexity = complexity
    
    for selection in node.selection_set.selections:
        field_name = selection.name.value if hasattr(selection, 'name') else None
        
        if field_name:
            field_cost = COMPLEXITY_COSTS.get(field_name, 1)
            total_complexity += field_cost
            
            if hasattr(selection, 'selection_set') and selection.selection_set:
                total_complexity += calculate_query_complexity(selection, 0)
    
    return total_complexity


def count_aliases(node, aliases=None):
    if aliases is None:
        aliases = set()
    
    if not hasattr(node, 'selection_set') or not node.selection_set:
        return len(aliases)
    
    for selection in node.selection_set.selections:
        if hasattr(selection, 'alias') and selection.alias:
            aliases.add(selection.alias.value)
            if len(aliases) > MAX_ALIASES:
                raise GraphQLError(f"Too many aliases. Maximum {MAX_ALIASES} aliases allowed.")
        
        if hasattr(selection, 'selection_set'):
            count_aliases(selection, aliases)
    
    return len(aliases)


def validate_query_security(document):
    rate_limit_check()
    
    for definition in document.definitions:
        if hasattr(definition, 'selection_set'):
            calculate_query_depth(definition)
            complexity = calculate_query_complexity(definition)
            if complexity > MAX_QUERY_COMPLEXITY:
                raise GraphQLError(f"Query complexity {complexity} exceeds maximum {MAX_QUERY_COMPLEXITY}")
            count_aliases(definition)


def check_batch_query(query_string):
    if query_string.count('query') > 5:
        raise GraphQLError("Batch queries are limited to 5 operations")


# GraphQL Types
class Review(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user_id = graphene.ID()
    rating = graphene.Int()
    comment = graphene.String()
    created_at = graphene.String()


class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()
    description = graphene.String()
    reviews = graphene.List(Review)
    
    def resolve_reviews(self, info):
        return [r for r in REVIEWS if r['product_id'] == self.id]


class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    products = graphene.List(Product)
    
    def resolve_products(self, info):
        return [Product(**p) for p in PRODUCTS if p['category_id'] == self.id]


class Query(graphene.ObjectType):
    products = graphene.List(
        Product,
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        category_id=graphene.ID()
    )
    product = graphene.Field(Product, id=graphene.ID(required=True))
    
    categories = graphene.List(
        Category,
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0)
    )
    category = graphene.Field(Category, id=graphene.ID(required=True))
    
    reviews = graphene.List(
        Review,
        product_id=graphene.ID(),
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0)
    )
    review = graphene.Field(Review, id=graphene.ID(required=True))
    
    def resolve_products(self, info, limit=10, offset=0, category_id=None):
        if limit > 100:
            raise GraphQLError("Limit cannot exceed 100")
        
        products = PRODUCTS
        if category_id:
            products = [p for p in products if p['category_id'] == category_id]
        
        return [Product(**p) for p in products[offset:offset + limit]]
    
    def resolve_product(self, info, id):
        product = next((p for p in PRODUCTS if p['id'] == id), None)
        if not product:
            raise GraphQLError(f"Product with id {id} not found")
        return Product(**product)
    
    def resolve_categories(self, info, limit=10, offset=0):
        if limit > 100:
            raise GraphQLError("Limit cannot exceed 100")
        
        return [Category(**c) for c in CATEGORIES[offset:offset + limit]]
    
    def resolve_category(self, info, id):
        category = next((c for c in CATEGORIES if c['id'] == id), None)
        if not category:
            raise GraphQLError(f"Category with id {id} not found")
        return Category(**category)
    
    def resolve_reviews(self, info, product_id=None, limit=10, offset=0):
        if limit > 100:
            raise GraphQLError("Limit cannot exceed 100")
        
        reviews = REVIEWS
        if product_id:
            reviews = [r for r in reviews if r['product_id'] == product_id]
        
        return [Review(**r) for r in reviews[offset:offset + limit]]
    
    def resolve_review(self, info, id):
        review = next((r for r in REVIEWS if r['id'] == id), None)
        if not review:
            raise GraphQLError(f"Review with id {id} not found")
        return Review(**review)


schema = graphene.Schema(query=Query)


class SecureGraphQLView(GraphQLView):
    def dispatch_request(self):
        try:
            data = self.parse_body()
            query = data.get('query', '')
            
            check_batch_query(query)
            
            return super().dispatch_request()
        except GraphQLError as e:
            return jsonify({'errors': [{'message': str(e)}]}), 400
        except Exception as e:
            return jsonify({'errors': [{'message': 'Internal server error'}]}), 500
    
    def execute_graphql_request(self, *args, **kwargs):
        try:
            document = kwargs.get('document')
            if document:
                validate_query_security(document)
        except GraphQLError as e:
            return None, [e]
        
        return super().execute_graphql_request(*args, **kwargs)


